mapper.update:
UPDATE TRIP

           NAME        = #{name,       jdbcType=VARCHAR},
      START_DATE  = #{startDate,  jdbcType=VARCHAR},
        END_DATE    = #{endDate,    jdbcType=VARCHAR}

WHERE TRIP_ID = #{tripId,       jdbcType=VARCHAR}

MERGE INTO TRIP_DAY target USING (
SELECT #{day.tripDayId, jdbcType=VARCHAR} AS TRIP_DAY_ID, #{tripId, jdbcType=VARCHAR} AS TRIP_ID, #{day.indexSort, jdbcType=INTEGER} AS INDEX_SORT FROM DUAL
) source ON (target.TRIP_DAY_ID = source.TRIP_DAY_ID) WHEN MATCHED THEN UPDATE SET target.INDEX_SORT = source.INDEX_SORT WHEN NOT MATCHED THEN INSERT (TRIP_ID, INDEX_SORT) VALUES (source.TRIP_ID, source.INDEX_SORT)
